#include<bits/stdc++.h>
using namespace std;
bool vis[1010][1010][2];
int a[1010][1010],n,m;
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};
struct node
{
    int x,y,flag,dis;
};
int main()
{
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    queue<node> q;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            if(a[i][j]==2)
            {
                q.push((node){i,j,0,0});
                vis[i][j][0]=true;
            }
        }
    }
    while(!q.empty())
    {
        node t=q.front();
        q.pop();
        if(a[t.x][t.y]==3&&t.flag)
        {
            printf("%d",t.dis);
            return 0;
        }
        for(int i=0;i<4;i++)
        {
            node t1=(node){t.x+dx[i],t.y+dy[i],t.flag,t.dis+1};
            if(t1.x<1||t1.x>n||t1.y<1||t1.y>m||vis[t1.x][t1.y][t1.flag]||a[t1.x][t1.y]==1)
            {
                continue;
            }
            if(a[t1.x][t1.y]==4)
            {
                t1.flag=1;
            }
            vis[t1.x][t1.y][t1.flag]=1;
            q.push(t1);
        }
    }
    return 0;
}
